select v_1 as "p_brand", v_2 as "p_type", v_3 as "p_size", v_4 as "supplier_cnt" from (select v_5 as v_1, v_6 as v_2, v_7 as v_3, count(distinct v_8) as v_4 from (select * from (select * from (select * from (select "p_partkey" as v_9, "p_name" as v_10, "p_mfgr" as v_11, "p_brand" as v_5, "p_type" as v_6, "p_size" as v_7, "p_container" as v_12, "p_retailprice" as v_13, "p_comment" as v_14 from "part") s where ((v_5 <> 'Brand#45') and ( not (v_6 like 'MEDIUM POLISHED%'))) and (v_7 in (cast('49' as integer), cast('14' as integer), cast('23' as integer), cast('45' as integer), cast('19' as integer), cast('3' as integer), cast('36' as integer), cast('9' as integer)))) l inner join (select "ps_partkey" as v_15, "ps_suppkey" as v_8, "ps_availqty" as v_16, "ps_supplycost" as v_17, "ps_comment" as v_18 from "partsupp") r on v_9 = v_15) l where not exists(select * from (select * from (select "s_suppkey" as v_19, "s_name" as v_20, "s_address" as v_21, "s_nationkey" as v_22, "s_phone" as v_23, "s_acctbal" as v_24, "s_comment" as v_25 from "supplier") s where v_25 like '%Customer%Complaints%') r where v_8 = v_19)) s group by 1, 2, 3) s order by v_4 desc, v_1, v_2, v_3
